const items = $input.all();
const updatedItems = items.map((item) => {
  let imageUrl = item?.json?.choices[0]?.message?.images[0]?.image_url?.url;
  if (imageUrl && imageUrl.startsWith("data:image/png;base64,")) {
    imageUrl = imageUrl.replace("data:image/png;base64,", "");
  }
  item.json.imageUrl = imageUrl;
  return item;
});
return updatedItems;
